### Android Document Scanner with ML Kit

Source: https://context7.com/dariyd/react-native-document-scanner/llms.txt

Implements document scanning on Android using Google ML Kit's Document Scanner API. Handles activity result handling and image processing with quality compression. Supports JPEG and PDF output formats.

```java
// DocumentScannerModule.java - Core Android implementation
package com.docscanner;

import com.google.mlkit.vision.documentscanner.GmsDocumentScanner;
import com.google.mlkit.vision.documentscanner.GmsDocumentScannerOptions;
import com.google.mlkit.vision.documentscanner.GmsDocumentScanning;

@ReactMethod
public void launchScanner(ReadableMap options, Callback callback) {
    Activity currentActivity = getCurrentActivity();

    // Configure ML Kit scanner
    GmsDocumentScannerOptions scannerOptions = new GmsDocumentScannerOptions.Builder()
        .setGalleryImportAllowed(false)
        .setPageLimit(10)
        .setResultFormats(
            GmsDocumentScannerOptions.RESULT_FORMAT_JPEG,
            GmsDocumentScannerOptions.RESULT_FORMAT_PDF
        )
        .setScannerMode(GmsDocumentScannerOptions.SCANNER_MODE_FULL)
        .build();

    GmsDocumentScanner scanner = GmsDocumentScanning.getClient(scannerOptions);

    scanner.getStartScanIntent(currentActivity)
        .addOnSuccessListener(intentSender -> {
            currentActivity.startIntentSenderForResult(
                intentSender,
                DOCUMENT_SCAN_REQUEST,
                null, 0, 0, 0
            );
        })
        .addOnFailureListener(e -> {
            callback.invoke(Map.of(
                "error", true,
                "errorMessage", e.getMessage()
            ));
        });
}

// Process scan results with quality compression
private WritableMap processImage(Uri imageUri) {
    Bitmap bitmap = BitmapFactory.decodeStream(
        contentResolver.openInputStream(imageUri)
    );

    // Apply quality setting
    double quality = options.getDouble("quality");
    ByteArrayOutputStream outputStream = new ByteArrayOutputStream();
    bitmap.compress(
        Bitmap.CompressFormat.JPEG,
        (int)(quality * 100),
        outputStream
    );

    // Save to cache
    File cacheFile = new File(getCacheDir(), UUID.randomUUID().toString() + ".jpg");
    FileOutputStream fos = new FileOutputStream(cacheFile);
    fos.write(outputStream.toByteArray());
    fos.close();

    return Map.of(
        "uri", Uri.fromFile(cacheFile).toString(),
        "width", bitmap.getWidth(),
        "height", bitmap.getHeight(),
        "fileSize", outputStream.size(),
        "type", "image/jpeg"
    );
}

```

